                      {o.sealedAt && <div className="text-amber-700 dark:text-amber-400">Sealed: {o.sealedAt}</div>}
                      {o.dispatchedAt && <div className="text-emerald-700 dark:text-emerald-400">Dispatched: {o.dispatchedAt}</div>}
