              const sevColors: Record<string, string> = { HIGH: 'border-orange-300 bg-orange-50/30', MEDIUM: 'border-amber-200 bg-amber-50/20', CRITICAL: 'border-rose-400 bg-rose-50/30', DISASTER: 'border-red-500 bg-red-50/30' }
