                      {wo.status === 'PENDING' && <Button size="sm" variant="ghost" className="h-7 text-[11px] text-emerald-600">Start</Button>}
                      <Button size="sm" variant="ghost" className="h-7 text-[11px]"><Eye className="h-3 w-3" /></Button>
